import 'dart:io';

import 'package:buritto/models/mood.dart';
import 'package:buritto/models/symptom.dart';
import 'package:statistics/statistics.dart';

void main() {
  for (final (profile, seed) in [
    ('normal', _normalSeed),
    ('pcos', _pcosSeed),
  ]) {
    stdout.write('Building $profile... ');
    final monitor = _buildMonitor(seed);
    final path = 'assets/population/network_$profile.json';
    File(path).writeAsStringSync(monitor.toJsonEncoded(pretty: true));
    stdout.write('saved ($path)\n');
  }
}

BayesEventMonitor _buildMonitor(List<List<String>> seed) {
  final monitor = BayesEventMonitor('cycleMonitor');
  for (final event in seed) {
    final Map<String, String> vals = {};
    for (final e in event) {
      final int i = e.indexOf('=');
      vals[e.substring(0, i)] = e.substring(i + 1);
    }

    final String phase = vals['PHASE']!;

    monitor.notifyEvent(['PHASE=$phase']);

    monitor.notifyEvent(['FLOW=${vals['FLOW']}', 'PHASE=$phase']);

    for (final s in Symptom.values) {
      final String key = 'SYMPTOM_${s.name.toUpperCase()}';
      monitor.notifyEvent(['$key=${vals[key] ?? 'FALSE'}', 'PHASE=$phase']);
    }

    for (final m in Mood.values) {
      final String key = 'MOOD_${m.name.toUpperCase()}';
      monitor.notifyEvent(['$key=${vals[key] ?? 'FALSE'}', 'PHASE=$phase']);
    }

    if (vals.containsKey('DISCHARGE')) monitor.notifyEvent(['DISCHARGE=${vals['DISCHARGE']}', 'PHASE=$phase']);
    if (vals.containsKey('STRESS')) monitor.notifyEvent(['STRESS=${vals['STRESS']}', 'PHASE=$phase']);
    if (vals.containsKey('SLEEP')) monitor.notifyEvent(['SLEEP=${vals['SLEEP']}', 'PHASE=$phase']);
    if (vals.containsKey('SEX')) monitor.notifyEvent(['SEX=${vals['SEX']}', 'PHASE=$phase']);
  }
  return monitor;
}

